def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        penalty = 1.0
        for j in range(1, 6):
            weight = (6 - j) * 0.15 + 0.1
            partial = (ratio ** j) * weight
            if partial > 0.4:
                partial *= 1.3
            if j % 2 == 0 and partial < 0.2:
                partial += 0.05 * j
            score += partial
        if capacity < item * 1.2:
            penalty *= 1.3
        elif capacity < item * 1.5:
            penalty *= 1.1
        else:
            penalty *= 0.9
        if ratio < 0.3:
            penalty *= 0.8
            for k in range(3):
                score += 0.02 * (k + 1)
        elif ratio > 0.8:
            penalty *= 1.4
            for k in range(2):
                score -= 0.03 * (k + 1)
        if score < 0:
            score = 0
        priorities[i] = score * penalty
    return priorities
